patch:
diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 7bff13d59528..7ca033a57353 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -35,6 +35,7 @@
 #include "llvm/Analysis/TargetLibraryInfo.h"
 #include "llvm/Analysis/ValueTracking.h"
 #include "llvm/Analysis/VectorUtils.h"
+#include "llvm/IR/ConstantFPRange.h"
 #include "llvm/IR/ConstantRange.h"
 #include "llvm/IR/DataLayout.h"
 #include "llvm/IR/Dominators.h"
@@ -1849,6 +1850,27 @@ static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
                  ? static_cast<Value *>(LHS)
                  : ConstantInt::getBool(LHS->getType(), !IsAnd);
   }
+  // Look for this pattern: {and/or} (fcmp X, C0), (fcmp X, C1)).
+  // The comparisons must have the same operand and both compare against constants.
+  if (LHS0 == RHS0) {
+    const APFloat *C0, *C1;
+    if (match(LHS1, m_APFloat(C0)) && match(RHS1, m_APFloat(C1)) &&
+        &C0->getSemantics() == &C1->getSemantics()) {
+      auto Range0 = ConstantFPRange::makeExactFCmpRegion(PredL, *C0);
+      auto Range1 = ConstantFPRange::makeExactFCmpRegion(PredR, *C1);
+      if (Range0 && Range1) {
+        // Is one range a superset of the other?
+        // If this is and-of-compares, take the smaller set:
+        // (fcmp olt X, 4.0) && (fcmp olt X, 42.0) --> fcmp olt X, 4.0
+        // If this is or-of-compares, take the larger set:
+        // (fcmp olt X, 4.0) || (fcmp olt X, 42.0) --> fcmp olt X, 42.0
+        if (Range1->contains(*Range0))
+          return IsAnd ? LHS : RHS;
+        if (Range0->contains(*Range1))
+          return IsAnd ? RHS : LHS;
+      }
+    }
+  }

   return nullptr;
 }

